import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import QRCode from 'react-qr-code';
import Navbar from '../../components/public/Navbar';
import API from '../../utils/api';

const DEPARTMENTS = ['BCA', 'MCA', 'BBA', 'MBA', 'B.Com', 'B.Sc', 'B.Tech', 'M.Tech', 'BA', 'MA', 'B.Ed', 'Other'];

const emptyPlayer = () => ({ name: '', uucms: '', phone: '', department: '' });

export default function RegisterPage() {
  const { eventId } = useParams();
  const navigate = useNavigate();
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [players, setPlayers] = useState([emptyPlayer()]);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    API.get('/events').then(r => {
      setEvents(r.data);
      if (eventId) {
        const ev = r.data.find(e => e._id === eventId);
        if (ev) selectEvent(ev);
      }
    });
  }, [eventId]);

  const selectEvent = (ev) => {
    setSelectedEvent(ev);
    if (ev.type === 'team') {
      setPlayers(Array.from({ length: ev.teamSize }, () => emptyPlayer()));
    } else {
      setPlayers([emptyPlayer()]);
    }
  };

  const updatePlayer = (idx, field, value) => {
    setPlayers(prev => prev.map((p, i) => i === idx ? { ...p, [field]: value } : p));
  };

  const addSubstitute = () => {
    setPlayers(prev => [...prev, { ...emptyPlayer(), isSubstitute: true }]);
  };

  const removePlayer = (idx) => {
    setPlayers(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSubmit = async () => {
    if (!selectedEvent) return toast.error('Please select an event');
    for (let i = 0; i < players.length; i++) {
      const p = players[i];
      if (!p.name || !p.uucms || !p.phone || !p.department) {
        return toast.error(`Please fill all fields for Player ${i + 1}`);
      }
    }

    setLoading(true);
    try {
      const res = await API.post('/registrations', { eventId: selectedEvent._id, players });
      setSuccess(res.data);
      toast.success('Registered successfully! 🎉');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-gray-50">
        <Navbar />
        <div className="max-w-4xl mx-auto px-4 py-12">
          <div className="bg-white rounded-2xl p-8 shadow-sm border border-gray-100 text-center">
            <div className="text-6xl mb-4">🎉</div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">Registration Successful!</h2>
            {success.teamId && <p className="text-blue-700 font-semibold mb-4">Team ID: {success.teamId}</p>}

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mt-8">
              {success.players.map((player, i) => (
                <div key={i} className="border border-gray-200 rounded-xl p-4">
                  <p className="font-semibold text-gray-900 mb-1">{player.name}</p>
                  <p className="text-sm text-gray-500 mb-3">{player.uucms} • {player.department}</p>
                  {player.isSubstitute && <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full mb-2 inline-block">Substitute</span>}
                  <div className="flex justify-center">
                    <QRCode value={player.qrCode || JSON.stringify({ name: player.name, uucms: player.uucms })} size={100} />
                  </div>
                  <p className="text-xs text-gray-400 mt-2">Show this QR at check-in</p>
                </div>
              ))}
            </div>

            <button onClick={() => { setSuccess(null); setPlayers([emptyPlayer()]); setSelectedEvent(null); }} className="btn-primary mt-8 px-8">
              Register Another
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />
      <div className="max-w-4xl mx-auto px-4 py-12">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Event Registration</h1>
        <p className="text-gray-500 mb-8">Fill in player details to register</p>

        {/* Event Selection */}
        <div className="card mb-6">
          <h2 className="font-semibold text-gray-800 mb-3">Step 1: Select Event</h2>
          <select className="input-field" value={selectedEvent?._id || ''} onChange={e => selectEvent(events.find(ev => ev._id === e.target.value))}>
            <option value="">-- Choose an Event --</option>
            {events.map(ev => <option key={ev._id} value={ev._id}>{ev.title} ({ev.type === 'team' ? `Team - ${ev.teamSize} players` : 'Individual'})</option>)}
          </select>
        </div>

        {/* Player Form */}
        {selectedEvent && (
          <div className="card">
            <h2 className="font-semibold text-gray-800 mb-4">
              Step 2: Player Details — <span className="text-blue-600">{selectedEvent.title}</span>
            </h2>

            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="px-3 py-2 text-left text-gray-600 font-medium w-16">Player</th>
                    <th className="px-3 py-2 text-left text-gray-600 font-medium">Name *</th>
                    <th className="px-3 py-2 text-left text-gray-600 font-medium">UUCMS No. *</th>
                    <th className="px-3 py-2 text-left text-gray-600 font-medium">Phone *</th>
                    <th className="px-3 py-2 text-left text-gray-600 font-medium">Department *</th>
                    {selectedEvent.type === 'team' && <th className="px-3 py-2"></th>}
                  </tr>
                </thead>
                <tbody>
                  {players.map((player, idx) => {
                    const isMainPlayer = idx < selectedEvent.teamSize || selectedEvent.type === 'single';
                    return (
                      <tr key={idx} className={`border-t border-gray-100 ${player.isSubstitute ? 'bg-yellow-50' : ''}`}>
                        <td className="px-3 py-2 font-medium text-gray-500">
                          {player.isSubstitute ? `Sub ${idx - selectedEvent.teamSize + 1}` : `P${idx + 1}`}
                        </td>
                        <td className="px-3 py-2"><input className="input-field" placeholder="Full name" value={player.name} onChange={e => updatePlayer(idx, 'name', e.target.value)} /></td>
                        <td className="px-3 py-2"><input className="input-field" placeholder="U02CG23S0001" value={player.uucms} onChange={e => updatePlayer(idx, 'uucms', e.target.value)} /></td>
                        <td className="px-3 py-2"><input className="input-field" placeholder="Phone" value={player.phone} onChange={e => updatePlayer(idx, 'phone', e.target.value)} /></td>
                        <td className="px-3 py-2">
                          <select className="input-field" value={player.department} onChange={e => updatePlayer(idx, 'department', e.target.value)}>
                            <option value="">Select dept</option>
                            {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                          </select>
                        </td>
                        {selectedEvent.type === 'team' && (
                          <td className="px-3 py-2">
                            {player.isSubstitute && (
                              <button onClick={() => removePlayer(idx)} className="text-red-500 hover:text-red-700 text-xs">✕</button>
                            )}
                          </td>
                        )}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            {selectedEvent.type === 'team' && (
              <button onClick={addSubstitute} className="mt-3 text-sm text-blue-600 hover:text-blue-800 border border-blue-200 hover:border-blue-400 px-4 py-2 rounded-lg transition-colors">
                + Add Substitute Player
              </button>
            )}

            <button onClick={handleSubmit} disabled={loading} className="btn-primary mt-6 w-full py-3 text-base font-semibold rounded-xl">
              {loading ? 'Registering...' : 'Submit Registration 🚀'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
